SELECT completion_status 
FROM puzzle_completions 
WHERE team_id = 1;

SELECT team_id
FROM puzzle_completions
WHERE incorrect_guesses = (SELECT MAX(incorrect_guesses) FROM puzzle_completions);

SELECT user_id
FROM event_managers
WHERE event_id = 1;

SELECT COUNT(completion_id) AS total_completions
FROM puzzle_completions
WHERE team_id = 1;

SELECT COUNT(*) 
FROM puzzle_completions 
WHERE team_id IN (SELECT team_id FROM team_members WHERE user_id = 1);
